async function main() {
  await connectDB();
  console.log(`Updating ${updates.length} products with rich descriptions...\n`);
  let success = 0, fail = 0;
  for (const u of updates) {
    try {
      const p = await Product.findById(u.id);
      if (!p) { console.log(`NOT FOUND: ${u.id}`); fail++; continue; }
      p.description = u.description;
      await p.save();
      console.log(`OK: ${p.name} (${u.description.length} chars)`);
      success++;
    } catch (e) { console.log(`ERR: ${u.id} - ${e.message}`); fail++; }
  }
  console.log(`\nDone: ${success} updated, ${fail} errors`);
  process.exit(0);
}
main().catch(e => { console.error(e); process.exit(1); });
